import type { Player, SaveData } from '../types';

export interface SaveSlot {
    slot: string;
    player: string;
    level: number;
    timestamp: string;
    playTime: number;
}

export class SaveSystem {
    private engine: unknown;
    private isInitialized: boolean = false;
    private saveKey: string = 'unified_tavern_rpg_save';
    private autoSaveInterval: ReturnType<typeof setInterval> | null = null;

    constructor(engine: unknown) {
        this.engine = engine;
    }

    async init(): Promise<void> {
        if (this.isInitialized) return;

        console.log('[SaveSystem] 初始化保存系统...');

        this.startAutoSave();

        this.isInitialized = true;
        console.log('[SaveSystem] 保存系统初始化完成');
    }

    saveGame(slot: string = 'default'): boolean {
        const win = window as unknown as {
            game?: {
                player?: Player;
                currentView?: string;
                playTime?: number;
                state?: unknown;
                showNotification?: (msg: string, type: string) => void;
            };
            mapSystem?: { currentLocation?: string; playerPosition?: { x: number; y: number } };
            cardSystem?: { deck?: unknown[]; hand?: unknown[] };
            questSystem?: { activeQuests: unknown[]; completedQuests: unknown[] };
            upgradeSystem?: { skillPoints?: number };
        };
        const game = win.game;
        
        if (!game || !game.player) {
            console.warn('[SaveSystem] 无法保存：没有游戏进行中');
            return false;
        }

        try {
            const saveData: SaveData = {
                version: '3.0.0',
                timestamp: new Date().toISOString(),
                player: game.player,
                gameState: {
                    player: game.player,
                    currentLocation: '',
                    currentView: game.currentView || 'main-menu',
                    gameStarted: true,
                    paused: false,
                    gameTime: 0,
                    weather: { type: 'clear', intensity: 0, duration: 0, effects: [] },
                    time: { hour: 12, minute: 0, day: 1, month: 1, year: 1, period: 'noon' },
                    playTime: game.playTime || 0,
                    state: game.state
                },
                mapState: win.mapSystem ? {
                    currentLocation: win.mapSystem.currentLocation,
                    playerPosition: win.mapSystem.playerPosition
                } : undefined,
                cardState: win.cardSystem ? {
                    deck: win.cardSystem.deck,
                    hand: win.cardSystem.hand
                } : undefined,
                questState: win.questSystem ? {
                    activeQuests: win.questSystem.activeQuests,
                    completedQuests: win.questSystem.completedQuests
                } : undefined,
                upgradeState: win.upgradeSystem ? {
                    skillPoints: win.upgradeSystem.skillPoints
                } : undefined
            };

            const saveKey = slot === 'auto' ? this.saveKey + '_auto' : this.saveKey;
            localStorage.setItem(saveKey, JSON.stringify(saveData));

            console.log(`[SaveSystem] 游戏已保存到 ${saveKey}`);
            game.showNotification?.('游戏已保存', 'success');
            return true;
        } catch (error) {
            console.error('[SaveSystem] 保存失败:', error);
            return false;
        }
    }

    loadGame(slot: string = 'default'): boolean {
        const win = window as unknown as {
            game?: {
                player?: Player;
                playTime?: number;
                currentView?: string;
                state?: unknown;
                showNotification?: (msg: string, type: string) => void;
                switchView?: (view: string) => void;
                updateUI?: () => void;
            };
            mapSystem?: { currentLocation?: string; playerPosition?: { x: number; y: number } };
            cardSystem?: { deck?: unknown[]; hand?: unknown[] };
            questSystem?: { activeQuests: unknown[]; completedQuests: unknown[]; updateQuestUI?: () => void };
            upgradeSystem?: { skillPoints?: number };
        };
        const game = win.game;
        
        try {
            const saveKey = slot === 'auto' ? this.saveKey + '_auto' : this.saveKey;
            const saveDataStr = localStorage.getItem(saveKey);

            if (!saveDataStr) {
                console.warn('[SaveSystem] 没有找到存档');
                game?.showNotification?.('没有找到存档', 'warning');
                return false;
            }

            const saveData = JSON.parse(saveDataStr) as SaveData;

            if (!saveData.version || !saveData.player) {
                console.warn('[SaveSystem] 存档数据无效');
                game?.showNotification?.('存档数据无效', 'error');
                return false;
            }

            if (game) {
                game.player = saveData.player;
                game.playTime = saveData.gameState?.playTime || 0;
                game.currentView = saveData.gameState?.currentView || 'main-menu';
                game.state = saveData.gameState?.state;

                if (saveData.mapState && win.mapSystem) {
                    win.mapSystem.currentLocation = saveData.mapState.currentLocation;
                    win.mapSystem.playerPosition = saveData.mapState.playerPosition;
                }

                if (saveData.cardState && win.cardSystem) {
                    win.cardSystem.deck = saveData.cardState.deck || [];
                    win.cardSystem.hand = saveData.cardState.hand || [];
                }

                if (saveData.questState && win.questSystem) {
                    win.questSystem.activeQuests = saveData.questState.activeQuests || [];
                    win.questSystem.completedQuests = saveData.questState.completedQuests || [];
                    win.questSystem.updateQuestUI?.();
                }

                if (saveData.upgradeState && win.upgradeSystem) {
                    win.upgradeSystem.skillPoints = saveData.upgradeState.skillPoints;
                }

                game.updateUI?.();

                const mainMenu = document.getElementById('main-menu');
                const gameInterface = document.getElementById('game-interface');

                if (mainMenu) mainMenu.style.display = 'none';
                if (gameInterface) gameInterface.style.display = 'flex';

                game.switchView?.(game.currentView);

                console.log(`[SaveSystem] 游戏已从 ${saveKey} 读取`);
                game.showNotification?.('游戏已读取！', 'success');
            }

            return true;
        } catch (error) {
            console.error('[SaveSystem] 读取失败:', error);
            game?.showNotification?.('读取存档失败', 'error');
            return false;
        }
    }

    deleteSave(slot: string = 'default'): boolean {
        try {
            const saveKey = slot === 'auto' ? this.saveKey + '_auto' : this.saveKey;
            localStorage.removeItem(saveKey);

            console.log(`[SaveSystem] 存档 ${saveKey} 已删除`);
            return true;
        } catch (error) {
            console.error('[SaveSystem] 删除存档失败:', error);
            return false;
        }
    }

    getSaveList(): SaveSlot[] {
        const saves: SaveSlot[] = [];

        const mainSave = localStorage.getItem(this.saveKey);
        if (mainSave) {
            const data = JSON.parse(mainSave) as SaveData;
            saves.push({
                slot: 'default',
                player: data.player?.name || '未知',
                level: data.player?.level || 1,
                timestamp: data.timestamp,
                playTime: data.gameState?.playTime || 0
            });
        }

        const autoSave = localStorage.getItem(this.saveKey + '_auto');
        if (autoSave) {
            const data = JSON.parse(autoSave) as SaveData;
            saves.push({
                slot: 'auto',
                player: data.player?.name || '未知',
                level: data.player?.level || 1,
                timestamp: data.timestamp,
                playTime: data.gameState?.playTime || 0
            });
        }

        return saves;
    }

    exportSave(): boolean | null {
        const saveData = localStorage.getItem(this.saveKey);
        if (!saveData) {
            console.warn('[SaveSystem] 没有存档可导出');
            return null;
        }

        const blob = new Blob([saveData], { type: 'application/json' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `tavern_rpg_save_${new Date().toISOString().slice(0, 10)}.json`;
        a.click();
        URL.revokeObjectURL(url);

        console.log('[SaveSystem] 存档已导出');
        return true;
    }

    async importSave(file: File): Promise<boolean> {
        return new Promise((resolve, reject) => {
            const reader = new FileReader();

            reader.onload = (e): void => {
                try {
                    const result = e.target?.result;
                    if (!result || typeof result !== 'string') {
                        throw new Error('读取文件失败');
                    }
                    
                    const saveData = JSON.parse(result) as SaveData;

                    if (!saveData.version || !saveData.player) {
                        throw new Error('无效的存档文件');
                    }

                    localStorage.setItem(this.saveKey, JSON.stringify(saveData));

                    console.log('[SaveSystem] 存档已导入');
                    const win = window as unknown as { game?: { showNotification?: (msg: string, type: string) => void } };
                    win.game?.showNotification?.('存档已导入', 'success');

                    resolve(true);
                } catch (error) {
                    console.error('[SaveSystem] 导入存档失败:', error);
                    const win = window as unknown as { game?: { showNotification?: (msg: string, type: string) => void } };
                    win.game?.showNotification?.('导入存档失败', 'error');
                    reject(error);
                }
            };

            reader.onerror = (): void => {
                console.error('[SaveSystem] 读取文件失败');
                const win = window as unknown as { game?: { showNotification?: (msg: string, type: string) => void } };
                win.game?.showNotification?.('读取文件失败', 'error');
                reject(new Error('读取文件失败'));
            };

            reader.readAsText(file);
        });
    }

    private startAutoSave(): void {
        this.autoSaveInterval = setInterval(() => {
            const win = window as unknown as { game?: { player?: Player } };
            if (win.game?.player) {
                this.saveGame('auto');
                console.log('[SaveSystem] 自动保存完成');
            }
        }, 5 * 60 * 1000);
    }

    stopAutoSave(): void {
        if (this.autoSaveInterval) {
            clearInterval(this.autoSaveInterval);
            this.autoSaveInterval = null;
        }
    }
}

export default SaveSystem;
